1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	type Item = { type: string };
5	type QuoteStep = { op: "quote"; items: Array<Item> };
6	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Array<QuoteStep> };
7	
8	const BASE_PREMIUMS: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	  rune: 25,
14	};
15	
16	const sum = (xs: number[]): number => xs.reduce((a, b) => a + b, 0);
17	
18	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
19	const BLOCK_SIZE = 3;
20	const BLOCK_PREMIUM = 60;
21	
22	const countByType = (items: Item[]): Record<string, number> => {
23	  const counts: Record<string, number> = {};
24	  for (const item of items) {
25	    counts[item.type] = (counts[item.type] ?? 0) + 1;
26	  }
27	  return counts;
28	};
29	
30	const componentTypeBase = (type: string, count: number): number =>
31	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * BASE_PREMIUMS[type];
32	
33	const componentBaseFor = (items: Item[]): number => {
34	  const counts = countByType(items);
35	  return sum(Object.keys(counts).map((type) => componentTypeBase(type, counts[type])));
36	};
37	
38	const quotePremium = (step: QuoteStep): number => {
39	  const mainItems = step.items.filter((i) => !COMPONENT_TYPES.has(i.type));
40	  const componentItems = step.items.filter((i) => COMPONENT_TYPES.has(i.type));
41	  const mainBase = sum(mainItems.map((i) => BASE_PREMIUMS[i.type]));
42	  const componentBase = componentBaseFor(componentItems);
43	  const policyBase = mainBase + componentBase;
44	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
45	  return Math.ceil(policyBase + firstInsuranceSurcharge + PROCESSING_FEE);
46	};
47	
48	export const runScenario = (input: unknown): unknown => {
49	  const scenario = input as Scenario;
50	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step) }));
51	  return { results };
52	};
